<template>
  <div style="width: 40%; margin-left: 200px">
    <div style="margin-bottom: 50px; margin-left: 250px">您想要做评价吗？</div>
    <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="200px">
      <el-form-item label="图书标准码" prop="bookNo">
        <el-input v-model="ruleForm.bookNo" disabled="true"></el-input>
      </el-form-item>
      <el-form-item label="用户Id" prop="userId">
        <el-input v-model="ruleForm.userId" disabled="true"></el-input>
      </el-form-item>
      <el-form-item label="评论" prop="message">
        <el-input v-model="ruleForm.message"></el-input>
      </el-form-item>
    </el-form>
    <div style="margin-left: 250px; margin-top: 40px">
      <el-button type="primary" @click="save">提交</el-button>
      <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
      <!--            <el-button type="danger ">取消</el-button>-->
    </div>
  </div>
</template>

<script>
import request from "@/utils/request";
//导入请求
export default {
  name: "AddNote",
  data() {
    // 自定义的校验
    return {
      ruleForm: {
      },

      rules: {}
    }

  },
  created() {
    const bookNo = this.$route.query.bookNo;
    const userId = this.$route.query.userId;
    this.ruleForm.bookNo = bookNo;
    this.ruleForm.userId  = userId;
    // request.get('/book/list').then(res => {
    //   this.bookNos = res.data;
    // })
    // request.get('/user/list').then(res => {
    //   this.sid = res.data
    // })
  },
  methods: {

    save() {
      //this.$refs与ref关联的，可以获取dom元素和子组件实例，配合validate对整个表单进行校验，valid每个必填表单项都提交为true，否则为false，规范化的操作
      this.$refs['ruleForm'].validate((valid) => {
        if (valid) {
          request.post('/note/save', this.ruleForm).then(res => {
            if (res.code === '200') {
              this.$notify.success('添加成功')
              // 重置表单
              this.$refs['ruleForm'].resetFields();
              this.$router.push('NoteList');
            } else {
              this.$notify.error(res.msg)
            }
          })
        }
      })

    },
    change() {
      this.$router.push('borrowList')
    },
    handleChange() {

    }
  }
}
</script>

